const body = $input.first().json.body || $input.first().json;
const eventType = body.event || body.message_type || 'unknown';
const messageId = body.id || body.message_id || null;
const conversationId = body.conversation?.id || body.conversation_id || null;
const accountId = body.account?.id || body.account_id || null;
const content = body.content || body.message?.content || '';
const attachments = body.attachments || body.message?.attachments || [];

let tipoConteudo = 'texto';
let conteudoFinal = content;
let mediaUrl = null;

if (attachments && attachments.length > 0) {
  const att = attachments[0];
  const fileType = att.file_type || att.content_type || '';
  if (fileType.includes('audio') || att.data_url?.includes('audio')) {
    tipoConteudo = 'audio';
    mediaUrl = att.data_url || att.file_url || null;
    conteudoFinal = content || '[Áudio recebido]';
  } else if (fileType.includes('image') || att.data_url?.includes('image')) {
    tipoConteudo = 'imagem';
    mediaUrl = att.data_url || att.file_url || null;
    conteudoFinal = content || '[Imagem recebida]';
  } else {
    tipoConteudo = 'documento';
    mediaUrl = att.data_url || att.file_url || null;
    conteudoFinal = content || '[Documento recebido]';
  }
}

const rawPhone = body.meta?.sender?.phone_number
  || body.conversation?.meta?.sender?.phone_number
  || body.sender?.phone_number
  || body.contact?.phone_number
  || '';

// ✅ CORREÇÃO: normalização robusta para E.164 sem +
let telefone = rawPhone.replace(/\D/g, ''); // remove +, espaços, parênteses, hífen

// Se veio com 55 na frente mas tem 13 dígitos (55 + 11), está correto
// Se tem 11 dígitos (DDD + número), adiciona 55
if (telefone.length === 11 && !telefone.startsWith('55')) {
  telefone = '55' + telefone;
// Se tem 10 dígitos (DDD + número sem 9), adiciona 55
} else if (telefone.length === 10 && !telefone.startsWith('55')) {
  telefone = '55' + telefone;
// ✅ NOVO: Se tem 13 dígitos começando com 55 mas com dígito 9 duplicado (ex: 5561981889041 → ok)
} else if (telefone.length === 13 && telefone.startsWith('55')) {
  // já está correto, mantém
  telefone = telefone;
// ✅ NOVO: Se ainda assim ficou com comprimento errado, tenta recompor
} else if (telefone.length > 13) {
  // pega os últimos 13 dígitos (caso venha com código de país duplo)
  telefone = telefone.slice(-13);
  if (!telefone.startsWith('55')) telefone = '55' + telefone.slice(-11);
}

const telefoneValido = telefone.length >= 12 && telefone.length <= 13;

// ✅ NOVO: também normaliza para salvar no banco consistentemente
// Garante que o telefone gerado pelo simulador/site também bata com o do WhatsApp
const telefoneNormalizado = telefone; // já está em formato E.164 sem +

const nomeContato = body.meta?.sender?.name
  || body.conversation?.meta?.sender?.name
  || body.sender?.name
  || body.contact?.name
  || 'Desconhecido';

const temConteudo = (conteudoFinal && conteudoFinal.trim().length > 0) || attachments.length > 0;
const isInbound = body.message_type === 'incoming' || body.message_type === undefined;

const eventId = messageId
  ? `msg_${messageId}`
  : `evt_${conversationId}_${Date.now()}_${Math.random().toString(36).substr(2,6)}`;

return [{
  json: {
    eventId,
    eventType,
    messageId,
    conversationId,
    accountId,
    telefone: telefoneNormalizado,
    telefoneValido,
    nomeContato,
    conteudo: conteudoFinal,
    tipoConteudo,
    mediaUrl,
    temConteudo,
    isInbound,
    rawBody: body
  }
}];

// FIX BUG 1: Normaliza saída do Registrar Evento para lidar com:
// - Tabela não existente (erro → json sem is_new)
// - ON CONFLICT DO NOTHING sem retorno (duplicado legítimo)
// - INSERT bem-sucedido (retorna id + is_new=true)

const result = $input.first().json;
const eventIdOrigem = $('Extrair Info (Robusto)').first().json.eventId;

// Se tem id no retorno → INSERT funcionou → evento novo
if (result.id != null) {
  return [{ json: { ...result, is_new: true } }];
}

// Se tem error mas a tabela não existe → tratar como novo (não bloquear)
if (result.error || result.message) {
  // Tabela pode não existir ainda → deixa passar como novo
  return [{ json: { id: null, event_id: eventIdOrigem, is_new: true, table_missing: true } }];
}

// Sem id e sem erro → ON CONFLICT DO NOTHING acionou → duplicado real
return [{ json: { id: null, event_id: eventIdOrigem, is_new: false } }];

const upsertConversa = $('Upsert Conversa').first().json;
const mensagens = $input.all();

let leadInfo = {};
try {
  leadInfo = $('Atualizar Lead').first().json;
} catch (e) {
  try {
    leadInfo = $('Criar Lead').first().json;
  } catch (e2) {
    leadInfo = {};
  }
}

const leadId = upsertConversa.lead_id;

const historico = mensagens
  .filter(m => m.json && m.json.conteudo)
  .reverse()
  .map(m => `[${m.json.direcao === 'inbound' ? 'Cliente' : 'Agente'}]: ${m.json.conteudo}`)
  .join('\n');

const prompt = `Você é um analista de crédito especialista. Analise a conversa abaixo e retorne APENAS um JSON válido, sem markdown, sem explicações.

LEAD ATUAL:
- ID: ${leadId}
- Nome: ${leadInfo.nome || 'Desconhecido'}
- Status atual: ${leadInfo.status || 'novo'}
- Etapa atual: ${leadInfo.etapa_funil || 'novo'}
- Score atual: ${leadInfo.score_ia || 0}

HISTÓRICO DA CONVERSA (mais recente por último):
${historico || 'Sem histórico disponível'}

Retorne EXATAMENTE este JSON (sem markdown):
{
  "score": <número 0-100>,
  "temperatura": <"frio"|"morno"|"quente"|"urgente">,
  "etapa_sugerida": <"novo"|"contato_feito"|"qualificado"|"proposta_enviada"|"negociacao"|"documentacao"|"aprovacao"|"ganho"|"perdido">,
  "resumo": <"resumo em 1-2 frases do perfil do lead">,
  "proxima_acao": <"próxima ação recomendada">,
  "probabilidade_conversao": <número 0-100>,
  "documentos_faltando": [],
  "pontos_positivos": [],
  "pontos_atencao": [],
  "nome_identificado": null,
  "empresa_identificada": null,
  "produto_interesse": null,
  "valor_estimado": null
}`;

return [{ json: { prompt, leadId, leadInfo } }];

const rawText = $input.first().json.text || $input.first().json.content || '';

const cleaned = rawText
  .replace(/```json\n?/gi, '')
  .replace(/```\n?/gi, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      parsed = JSON.parse(match[0]);
    } catch (e2) {
      parsed = {
        score: 0, temperatura: 'frio', etapa_sugerida: 'novo',
        resumo: 'Erro ao parsear resposta da IA',
        proxima_acao: 'Revisar manualmente',
        probabilidade_conversao: 0,
        documentos_faltando: [], pontos_positivos: [],
        pontos_atencao: ['Erro no processamento da IA'],
        nome_identificado: null, empresa_identificada: null,
        produto_interesse: null, valor_estimado: null
      };
    }
  } else {
    parsed = {
      score: 0, temperatura: 'frio', etapa_sugerida: 'novo',
      resumo: 'Sem resposta da IA',
      proxima_acao: 'Revisar manualmente',
      probabilidade_conversao: 0,
      documentos_faltando: [], pontos_positivos: [],
      pontos_atencao: ['Sem resposta da IA'],
      nome_identificado: null, empresa_identificada: null,
      produto_interesse: null, valor_estimado: null
    };
  }
}

return [{ json: { ...parsed, leadId: $('Montar Prompt').item.json.leadId } }];

